}

/* Disable transitions during active resize for immediate feedback */
.gemini-timeline-bar.timeline-resizing::before {
  transition: none !important;
}

/* Prevent text selection during resize drag */
.gemini-timeline-bar.timeline-resizing {
  user-select: none;
  -webkit-user-select: none;
}

.timeline-track {
  position: relative;
  width: 100%;
  height: 100%;
  overflow-y: auto;
  overflow-x: visible;
  background: transparent;
  padding-left: 2px;
  padding-right: 2px;
}

.timeline-track-content {
  position: relative;
  width: 100%;
  height: 100%;
}

.timeline-dot {
  position: absolute;
  left: 50%;
  top: calc(
    var(--timeline-track-padding) + (100% - 2 * var(--timeline-track-padding)) * var(--n, 0)
  );
  transform: translate(-50%, -50%);
  width: var(--timeline-hit-size);
  height: var(--timeline-hit-size);
  background: transparent;
  border: none;
  cursor: pointer;
  padding: 0;
  pointer-events: auto;
}

.timeline-dot::after {
  content: '';
  position: absolute;
  left: 50%;
  top: 50%;
  width: var(--timeline-dot-size);
  height: var(--timeline-dot-size);
  transform: translate(-50%, -50%);
  border-radius: 50%;
  background-color: var(--timeline-dot-color);
  transition:
    transform 0.15s ease,
    box-shadow 0.15s ease;
}

/* true punch-through: remove filled dot and draw only inner stroke to make host page visible */
html.dark .timeline-track,
