/* ==========================================================================
   Folder Import/Export Styles
   ========================================================================== */

/* Header actions container */
.gv-folder-header-actions {
  display: flex;
  align-items: center;
  gap: 4px;
}

/* Action buttons (import/export) */
.gv-folder-action-btn {
  background: none;
  border: none;
  padding: 4px;
  cursor: pointer;
  border-radius: 50%;
  color: var(--folder-icon-color);
  display: flex;
  align-items: center;
  justify-content: center;
  transition: background-color 0.2s ease;
  opacity: 0.9;
}

.gv-folder-action-btn:hover {
  background-color: rgba(0, 0, 0, 0.05);
  opacity: 1;
}

html.dark .gv-folder-action-btn:hover,
body.dark-theme .gv-folder-action-btn:hover,
[data-theme='dark'] .gv-folder-action-btn:hover,
[data-color-scheme='dark'] .gv-folder-action-btn:hover {
  background-color: rgba(255, 255, 255, 0.08);
}

.gv-folder-action-btn mat-icon {
  font-size: 18px;
  width: 18px;
  height: 18px;
}

/* Filter active state */
.gv-folder-action-btn.gv-filter-active {
  background-color: rgba(66, 133, 244, 0.15);
  opacity: 1;
}

.gv-folder-action-btn.gv-filter-active mat-icon {
  color: #4285f4;
}

html.dark .gv-folder-action-btn.gv-filter-active,
body.dark-theme .gv-folder-action-btn.gv-filter-active,
[data-theme='dark'] .gv-folder-action-btn.gv-filter-active,
[data-color-scheme='dark'] .gv-folder-action-btn.gv-filter-active {
  background-color: rgba(138, 180, 248, 0.2);
}

html.dark .gv-folder-action-btn.gv-filter-active mat-icon,
body.dark-theme .gv-folder-action-btn.gv-filter-active mat-icon,
[data-theme='dark'] .gv-folder-action-btn.gv-filter-active mat-icon,
[data-color-scheme='dark'] .gv-folder-action-btn.gv-filter-active mat-icon {
  color: #8ab4f8;
}

/* ==========================
   AI Studio specific tweaks
   - Compact spacing + icon fallbacks
   - Do NOT affect gemini.google UI
   - Let AI Studio manage sidebar width natively
   ========================== */

/* Allow folder container to adapt to native sidebar width */
.gv-aistudio-root ms-prompt-history-v3 {
  /* Ensure folder content doesn't overflow */
  overflow-x: hidden;
}

.gv-aistudio-root .nav-content.v3-left-nav {
  /* Just add padding for folder icons, don't force width */
  padding-right: 4px;
}

.gv-aistudio .gv-folder-header {
  padding: 6px 8px 6px 0;
  margin-bottom: 6px;
}

.gv-aistudio .gv-folder-title {
  font-size: 12px;
  opacity: 0.8;
}

.gv-aistudio .gv-folder-item-header {
  gap: 6px;
  padding: 6px 10px;
  /* Reserve space for more button only (pin is hidden by default) */
  padding-right: 10px;
  overflow: visible;
  min-height: 28px;
}

.gv-aistudio .gv-folder-name {
  font-size: 12px;
  /* Allow a bit more width visually */
  letter-spacing: 0.1px;
  /* Ensure folder name has minimum width to display at least a few characters */
  min-width: 40px;
  flex: 1;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.gv-aistudio .gv-folder-expand-btn {
  width: 18px;
  height: 18px;
}

.gv-aistudio .gv-folder-icon {
  font-size: 16px;
}

/* Reduce container/list side paddings to utilize width */
.gv-aistudio.gv-folder-container {
  padding-left: 2px;
  padding-right: 2px;
}

.gv-aistudio .gv-folder-list {
  padding-left: 0;
  padding-right: 0;
}

/* Make action buttons absolute so they don’t steal inline space */
.gv-aistudio .gv-folder-pin-btn,
.gv-aistudio .gv-folder-actions-btn {
  width: 24px;
  height: 24px;
  position: absolute;
  top: 50%;
  transform: translateY(-50%);
  margin: 0;
  overflow: visible;
  z-index: 1;
}

/* Pin button: hidden by default, show on hover to save space */
.gv-aistudio .gv-folder-pin-btn {
  opacity: 0;
  transition: opacity 0.15s ease;
}

/* More button: hidden by default, show on hover to save space */
.gv-aistudio .gv-folder-actions-btn {
  opacity: 0;
  transition: opacity 0.15s ease;
}

.gv-aistudio .gv-folder-item-header:hover .gv-folder-pin-btn,
.gv-aistudio .gv-folder-item-header:hover .gv-folder-actions-btn {
  opacity: 1;
}

.gv-aistudio .gv-folder-actions-btn {
  right: 6px;
}

.gv-aistudio .gv-folder-pin-btn {
  right: 28px;
}

.gv-aistudio .gv-folder-header-actions .gv-folder-action-btn {
  padding: 2px;
}

/* Ensure pin/more icons are perfectly centered and not clipped */
.gv-aistudio .gv-folder-pin-btn .google-symbols,
.gv-aistudio .gv-folder-actions-btn .google-symbols {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 24px;
  /* match button box */
  height: 24px;
  line-height: 24px;
  overflow: visible !important;
  /* never clip emoji */
}

.gv-aistudio .gv-folder-pin-btn .google-symbols::before,
.gv-aistudio .gv-folder-actions-btn .google-symbols::before {
  width: 24px;
  height: 24px;
  line-height: 24px;
  text-align: center;
  font-size: 20px;
  /* slightly larger for better visual balance */
}

/* Icon fallbacks: hide ligature text and use simple glyphs */
.gv-aistudio .gv-folder-pin-btn .google-symbols,
.gv-aistudio .gv-folder-add-btn .google-symbols,
.gv-aistudio .gv-folder-actions-btn .google-symbols,
.gv-aistudio .gv-folder-expand-btn .google-symbols,
.gv-aistudio .gv-folder-icon.google-symbols,
.gv-aistudio .gv-conversation-icon.google-symbols,
.gv-aistudio .gv-folder-action-btn .google-symbols,
.gv-aistudio .gv-conversation-star-btn .google-symbols,
.gv-aistudio .gv-conversation-remove-btn .google-symbols,
.gv-aistudio .gv-folder-uncategorized-header .google-symbols {
  font-family: inherit !important;
  /* Don’t rely on Material Symbols in aistudio */
  font-weight: 400;
  font-size: 0;
  /* Hide text like 'push_pin' */
  line-height: 20px;
  display: inline-block;
  width: 20px;
  /* bigger box to avoid clipping */
  height: 20px;
  overflow: hidden;
  vertical-align: middle;
}

.gv-aistudio .google-symbols::before {
  display: block;
  width: 20px;
  height: 20px;
  line-height: 20px;
  text-align: center;
  font-size: 18px;
}

/* Per-icon mappings */
.gv-aistudio .google-symbols[data-icon='expand_more']::before {
  content: '▾';
}

.gv-aistudio .google-symbols[data-icon='chevron_right']::before {
  content: '▸';
}

.gv-aistudio .google-symbols[data-icon='folder']::before {
  content: '📁';
  font-size: 16px;
}

.gv-aistudio .google-symbols[data-icon='chat']::before {
  content: '💬';
  font-size: 16px;
}

.gv-aistudio .google-symbols[data-icon='push_pin']::before {
  content: '📌';
  font-size: 16px;
}

.gv-aistudio .gv-folder-pin-btn[data-state='unpinned'] .google-symbols::before {
  content: '📍';
  font-size: 14px;
}

.gv-aistudio
  .gv-folder-item[data-pinned='true']
  > .gv-folder-item-header
  .gv-folder-pin-btn
  .google-symbols::before {
  content: '📌';
  color: #f59e0b;
}

/* Subtle highlight for pinned folders */
.gv-aistudio .gv-folder-item[data-pinned='true'] > .gv-folder-item-header {
  background-color: rgba(245, 158, 11, 0.08);
}

/* Aistudio conversation layout tweaks */
.gv-aistudio .gv-folder-conversation {
  overflow: visible;
}

/* AI Studio selected conversation style */
.gv-aistudio .gv-folder-conversation-selected {
  position: relative;
  background: linear-gradient(
    to right,
    var(--folder-selected-glow) 0%,
    transparent 100%
  ) !important;
  border-radius: 10px;
  transition: background 200ms ease;
}

.gv-aistudio .gv-folder-conversation-selected::before {
  content: '';
  position: absolute;
  left: 0;
  top: 50%;
  transform: translateY(-50%);
  width: 3px;
  height: 60%;
  border-radius: 0 2px 2px 0;
  background-color: var(--folder-selected-accent);
  opacity: 0.9;
  pointer-events: none;
}

.gv-aistudio .gv-folder-conversation-selected > * {
  position: relative;
  z-index: 1;
}

.gv-aistudio .gv-conversation-title {
  min-width: 0;
}

.gv-aistudio .gv-conversation-star-btn {
  margin-left: auto;
}

/* AI Studio: keep conversations readable with clear hierarchy */
.gv-aistudio .gv-folder-content {
  margin-left: 16px;
  padding-left: 10px;
  border-left: 1px solid var(--folder-border);
}

/* Root drop zone visuals */
.gv-aistudio .gv-folder-root-drop {
  margin: 4px 8px 0 8px;
  min-height: 28px;
  border-radius: 6px;
  border: 1px dashed var(--folder-border);
  color: var(--folder-icon-color);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 11px;
  opacity: 0.7;
}

.gv-aistudio .gv-folder-root-drop.gv-folder-dragover {
  background-color: var(--folder-dragover-bg);
  border-color: var(--folder-dragover-border);
  opacity: 1;
}

/* Uncategorized section styles */
.gv-aistudio .gv-folder-uncategorized {
  margin-top: 8px;
  padding-top: 8px;
  border-top: 1px solid var(--folder-border);
}

.gv-aistudio .gv-folder-uncategorized-header {
  display: flex;
  align-items: center;
  padding: 6px 10px;
  font-size: 12px;
  color: var(--folder-icon-color);
  opacity: 0.7;
}

.gv-aistudio .gv-folder-uncategorized-content {
  padding-left: 8px;
}

.gv-aistudio .google-symbols[data-icon='inbox']::before {
  content: '📥';
  font-size: 14px;
}

.gv-aistudio .google-symbols[data-icon='more_vert']::before {
  content: '⋮';
  font-size: 16px;
}

.gv-aistudio .google-symbols[data-icon='add']::before {
  content: '+';
  font-size: 16px;
}

.gv-aistudio .google-symbols[data-icon='download']::before {
  content: '⬇';
  font-size: 16px;
}

.gv-aistudio .google-symbols[data-icon='upload']::before {
  content: '⬆';
