/* Inline confirm popover for delete (floating and responsive) */
.gv-pm-confirm {
  position: fixed;
  background: rgba(2, 6, 23, 0.96);
  color: #e5e7eb;
  border: 1px solid rgba(255, 255, 255, 0.12);
  border-radius: 10px;
  padding: 6px 8px;
  display: inline-flex;
  gap: 8px;
  align-items: center;
  z-index: 2147483646;
  max-width: 280px;
  box-shadow: 0 8px 24px rgba(2, 6, 23, 0.4);
}

.gv-pm-confirm span {
  font-size: 12px;
  opacity: 0.95;
  line-height: 1.3;
  white-space: normal;
  flex: 1;
}

.gv-pm-confirm button {
  padding: 2px 8px;
  border-radius: 6px;
  border: 1px solid rgba(255, 255, 255, 0.18);
  background: rgba(31, 41, 55, 0.6);
  color: #e5e7eb;
  white-space: nowrap;
  font-size: 12px;
}

.gv-pm-confirm .gv-pm-confirm-yes {
  background: rgba(239, 68, 68, 0.18);
  border-color: rgba(239, 68, 68, 0.38);
  color: #fecaca;
}

.gv-pm-confirm button:hover {
  filter: brightness(1.05);
}

.gv-pm-confirm::after {
  content: '';
  position: absolute;
  width: 10px;
  height: 10px;
  background: rgba(2, 6, 23, 0.96);
  border: 1px solid rgba(255, 255, 255, 0.12);
  transform: rotate(45deg);
}

.gv-pm-confirm[data-side='left']::after {
  right: -6px;
  top: 50%;
  transform: translateY(-50%) rotate(45deg);
  border-left: none;
  border-bottom: none;
}

.gv-pm-confirm[data-side='right']::after {
  left: -6px;
  top: 50%;
  transform: translateY(-50%) rotate(45deg);
  border-right: none;
  border-top: none;
}

.gv-pm-drag {
  width: 10px;
  height: 14px;
  margin-left: -6px;
  margin-right: 6px;
  position: relative;
  opacity: 0.7;
  cursor: move;
}

.gv-pm-drag::before {
  content: '⠿';
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 10px;
}

.gv-locked .gv-pm-drag {
  cursor: default;
  opacity: 0.9;
}

/* ========================================
   PM Theme Toggle
   ======================================== */

.gv-pm-theme-toggle {
  width: 38px;
  height: 20px;
  border-radius: 999px;
  position: relative;
  cursor: pointer;
  flex-shrink: 0;
  border: none;
  padding: 0;
  background: linear-gradient(135deg, oklch(0.82 0.12 80), oklch(0.72 0.15 50));
  box-shadow:
    inset 0 1px 2px oklch(0 0 0 / 0.08),
    0 1px 3px oklch(0 0 0 / 0.06);
  transition:
    background 0.4s cubic-bezier(0.4, 0, 0.2, 1),
    box-shadow 0.3s ease;
  outline: none;
}

/* Thumb (white circle) */
.gv-pm-theme-toggle::before {
  content: '';
  position: absolute;
  top: 2px;
  left: 2px;
  width: 16px;
  height: 16px;
  border-radius: 50%;
  background: white;
  box-shadow: 0 1px 4px oklch(0 0 0 / 0.18);
  transition:
    transform 0.4s cubic-bezier(0.4, 0, 0.2, 1),
    background 0.4s ease,
    box-shadow 0.4s ease;
}

/* Emoji on the thumb */
.gv-pm-theme-toggle::after {
  content: '☀️';
  position: absolute;
  top: 2px;
  left: 2px;
  width: 16px;
  height: 16px;
  display: grid;
  place-items: center;
  font-size: 10px;
  line-height: 1;
  pointer-events: none;
  z-index: 1;
  transition: transform 0.4s cubic-bezier(0.4, 0, 0.2, 1);
}

.gv-pm-theme-toggle:hover {
  box-shadow:
    inset 0 1px 2px oklch(0 0 0 / 0.1),
    0 2px 8px oklch(0 0 0 / 0.12);
}

.gv-pm-theme-toggle:focus-visible {
  box-shadow:
    0 0 0 2px oklch(0.55 0.17 155 / 0.4),
    inset 0 1px 2px oklch(0 0 0 / 0.08);
}

/* Dark state — vibrant purple gradient */
.gv-pm-theme-toggle.gv-pm-theme-dark {
  background: linear-gradient(135deg, oklch(0.45 0.18 285), oklch(0.35 0.22 300));
}

.gv-pm-theme-toggle.gv-pm-theme-dark::before {
  transform: translateX(18px);
  background: white;
  box-shadow: 0 1px 4px oklch(0 0 0 / 0.25);
}

.gv-pm-theme-toggle.gv-pm-theme-dark::after {
  content: '🌙';
  transform: translateX(18px);
}

/* Smooth panel theme transition */
.gv-pm-panel.gv-pm-transitioning,
.gv-pm-panel.gv-pm-transitioning * {
  transition:
    background 0.4s ease,
    color 0.4s ease,
    border-color 0.4s ease,
    box-shadow 0.4s ease !important;
}

