  position: relative;
  cursor: pointer;
}

.gv-export-msg-selector {
  display: none;
  position: absolute;
  left: 8px;
  top: 50%;
  transform: translateY(-50%);
  z-index: 30;
}

.gv-export-select-mode .gv-export-msg-selector {
  display: flex;
  align-items: center;
  justify-content: center;
}

.gv-export-msg-checkbox {
  width: 22px;
  height: 22px;
  border-radius: 6px;
  border: 1px solid rgba(0, 0, 0, 0.15);
  background: rgba(255, 255, 255, 0.9);
  color: #64748b;
  cursor: pointer;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  transition: all 0.12s ease;
}

.gv-export-msg-checkbox:hover {
  border-color: rgba(22, 163, 74, 0.6);
  box-shadow: 0 0 0 2px rgba(22, 163, 74, 0.12);
}

.gv-export-msg-checkbox-mark {
  width: 8px;
  height: 4px;
  border-left: 2px solid transparent;
  border-bottom: 2px solid transparent;
  transform: rotate(-45deg) translate(0, -1px);
}

.gv-export-msg-checkbox[data-selected='true'] {
  background: #16a34a;
  border-color: #16a34a;
}

.gv-export-msg-checkbox[data-selected='true'] .gv-export-msg-checkbox-mark {
  border-left-color: #fff;
  border-bottom-color: #fff;
}

/* Dark theme for checkbox */
html.dark .gv-export-msg-checkbox,
html.dark-theme .gv-export-msg-checkbox,
.theme-host.dark-theme .gv-export-msg-checkbox {
  border-color: rgba(255, 255, 255, 0.2);
  background: rgba(19, 22, 28, 0.9);
  color: #8b98aa;
}

html.dark .gv-export-msg-checkbox:hover,
html.dark-theme .gv-export-msg-checkbox:hover,
.theme-host.dark-theme .gv-export-msg-checkbox:hover {
  border-color: rgba(128, 255, 176, 0.7);
  box-shadow: 0 0 0 2px rgba(128, 255, 176, 0.15);
}

.gv-export-msg-selected {
  box-shadow:
    0 0 0 1px rgba(34, 197, 94, 0.55),
    0 8px 18px rgba(34, 197, 94, 0.1);
}

.gv-export-select-bar {
  position: fixed;
  left: 50%;
  top: 12px;
  width: max-content;
  max-width: calc(100vw - 32px);
  transform: translateX(-50%);
  z-index: 2147483600;
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 14px;
  border-radius: 14px;
  background: rgba(13, 17, 23, 0.92);
  border: 1px solid rgba(255, 255, 255, 0.12);
  backdrop-filter: blur(10px);
  color: #e5ecf5;
  box-shadow:
    0 12px 30px rgba(0, 0, 0, 0.38),
    0 2px 8px rgba(0, 0, 0, 0.22);
  overflow-x: auto;
  scrollbar-width: none;
  /* Firefox */
}

.gv-export-select-bar::-webkit-scrollbar {
  display: none;
  /* Chrome, Safari, Opera */
}

.gv-export-select-all-toggle,
.gv-export-select-role-btn,
.gv-export-select-export-btn,
.gv-export-select-cancel-btn {
  border: 0;
  cursor: pointer;
  transition: all 0.12s ease;
}

.gv-export-select-all-toggle,
.gv-export-select-role-btn {
  min-width: 68px;
  flex-shrink: 0;
  height: 34px;
  padding: 0 12px;
  border-radius: 10px;
  background: rgba(255, 255, 255, 0.08);
  color: #e5ecf5;
  font-size: 13px;
  font-weight: 600;
  white-space: nowrap;
}

.gv-export-select-all-toggle[data-checked='true'],
.gv-export-select-role-btn[data-checked='true'],
.gv-export-select-role-btn:active {
  background: rgba(22, 163, 74, 0.24);
  color: #bbf7d0;
}

.gv-export-select-all-toggle:hover:not(:active),
.gv-export-select-role-btn:hover:not(:active) {
  background: rgba(255, 255, 255, 0.14);
}

.gv-export-select-count {
  min-width: 92px;
  flex-shrink: 0;
  text-align: center;
  color: #cfd8e3;
  font-size: 13px;
  font-weight: 600;
  white-space: nowrap;
}

.gv-export-select-export-btn {
  min-width: 74px;
  flex-shrink: 0;
  height: 34px;
  padding: 0 14px;
  border-radius: 10px;
  background: #1d4ed8;
  color: #fff;
  font-size: 13px;
  font-weight: 700;
  white-space: nowrap;
}

