  background: #2563eb;
}

.gv-export-select-export-btn:disabled {
  opacity: 0.45;
  cursor: not-allowed;
}

.gv-export-select-cancel-btn {
  width: 34px;
  flex-shrink: 0;
  height: 34px;
  border-radius: 10px;
  background: transparent;
  color: #a8b6c8;
  font-size: 20px;
  line-height: 1;
}

