  background: rgba(255, 255, 255, 0.1);
  color: #eef4ff;
}

.gv-export-progress-overlay {
  position: fixed;
  left: 50%;
  transform: translateX(-50%);
  top: 12px;
  z-index: 2147483645;
  pointer-events: none;
}

.gv-export-progress-card {
  min-width: 220px;
  max-width: min(360px, calc(100vw - 24px));
  padding: 9px 12px;
  border-radius: 999px;
  border: 1px solid rgba(15, 23, 42, 0.12);
  background: rgba(255, 255, 255, 0.92);
  color: #0f172a;
  box-shadow:
    0 10px 24px rgba(15, 23, 42, 0.16),
    0 2px 8px rgba(15, 23, 42, 0.08);
  backdrop-filter: blur(10px);
  display: grid;
  grid-template-columns: auto 1fr;
  grid-template-areas:
    'spinner title'
    'spinner desc';
  align-items: center;
  column-gap: 10px;
  row-gap: 1px;
}

.gv-export-progress-spinner {
  grid-area: spinner;
  width: 22px;
  height: 22px;
  border-radius: 999px;
  border: 2px solid rgba(100, 116, 139, 0.32);
  border-top-color: #2563eb;
  animation: gv-export-progress-spin 0.8s linear infinite;
}

.gv-export-progress-title {
  grid-area: title;
  font-size: 16px;
  font-weight: 700;
  color: #0f172a;
  line-height: 1.2;
}

.gv-export-progress-desc {
  grid-area: desc;
  font-size: 12px;
  color: #475569;
  line-height: 1.2;
}

html.dark .gv-export-progress-card,
