4→

  1→/**
  2→ * Rain Effect for Gemini — inspired by "The Garden of Words"
  3→ *
  4→ * A cinematic rain with depth layers, wind-angled streaks, and
  5→ * tiny splash ripples where drops hit the viewport floor.
  6→ *
  7→ * Graceful transitions: when switching effects or disabling, existing
  8→ * raindrops continue falling naturally with final splash ripples.
  9→ * New drops stop spawning, and the canvas is cleaned up once all
 10→ * particles and splashes have left the viewport.
 11→ *
 12→ * Visual approach:
 13→ * - Raindrops are thin, semi-transparent lines (not dots), drawn
 14→ *   at a slight wind angle (~8°) for realism.
 15→ * - Three depth layers: far mist, mid rain, near foreground.
 16→ *   Each layer has its own speed, length, opacity, and thickness.
 17→ * - When a drop reaches the bottom, it spawns a short-lived splash
 18→ *   ring that expands and fades out.
 19→ * - Colour: cool blue-grey (hsl 210–220) to evoke the melancholy
 20→ *   atmosphere of Shinjuku Gyoen in the rain.
 21→ */
 22→
 23→const CANVAS_ID = 'gv-rain-effect-canvas';
 24→const STORAGE_KEY = 'gvVisualEffect';
 25→const LEGACY_KEY = 'gvSnowEffect';
 26→const EFFECT_VALUE = 'rain';
 27→
 28→/** Wind angle in radians (~8° from vertical) */
 29→const WIND_ANGLE = 0.14;
 30→const WIND_DX = Math.sin(WIND_ANGLE);
 31→const WIND_DY = Math.cos(WIND_ANGLE);
 32→
 33→const LAYERS = [
 34→  // far — misty fine drizzle
 35→  {
 36→    count: 80,
 37→    length: [6, 14],
 38→    speed: [3, 6],
 39→    opacity: [0.06, 0.14],
 40→    width: [0.3, 0.6],
 41→  },
 42→  // mid — main rain
 43→  {
 44→    count: 60,
 45→    length: [14, 28],
 46→    speed: [7, 13],
 47→    opacity: [0.12, 0.25],
 48→    width: [0.5, 1.0],
 49→  },
 50→  // near — heavy foreground streaks
 51→  {
 52→    count: 30,
 53→    length: [26, 48],
 54→    speed: [12, 20],
 55→    opacity: [0.2, 0.38],
 56→    width: [0.8, 1.5],
 57→  },
 58→] as const;
 59→
 60→/** Maximum concurrent splashes */
 61→const MAX_SPLASHES = 24;
 62→
 63→interface Raindrop {
 64→  x: number;
 65→  y: number;
 66→  length: number;
 67→  speed: number;
 68→  opacity: number;
 69→  lineWidth: number;
 70→  /** Whether this drop can spawn a splash (only near/mid layers) */
 71→  canSplash: boolean;
 72→}
 73→
 74→interface Splash {
 75→  x: number;
 76→  y: number;
 77→  radius: number;
 78→  maxRadius: number;
 79→  opacity: number;
 80→  fadeSpeed: number;
 81→  expandSpeed: number;
 82→}
 83→
 84→/** Effect lifecycle: off → active ⇄ draining → off */
 85→let state: 'off' | 'active' | 'draining' = 'off';
 86→let canvas: HTMLCanvasElement | null = null;
 87→let ctx: CanvasRenderingContext2D | null = null;
 88→let animationFrameId: number | null = null;
 89→let drops: Raindrop[] = [];
 90→let splashes: Splash[] = [];
 91→let resizeHandler: (() => void) | null = null;
 92→let visibilityHandler: (() => void) | null = null;
 93→
 94→function rand(min: number, max: number): number {
 95→  return min + Math.random() * (max - min);
 96→}
 97→
 98→function createDrop(
 99→  canvasWidth: number,
100→  canvasHeight: number,
101→  layer: (typeof LAYERS)[number],
102→  randomY: boolean,
103→  canSplash: boolean,
104→): Raindrop {
105→  return {
106→    x: Math.random() * (canvasWidth + 100) - 50,
107→    y: randomY ? Math.random() * canvasHeight : -(Math.random() * canvasHeight * 0.3),
108→    length: rand(layer.length[0], layer.length[1]),
109→    speed: rand(layer.speed[0], layer.speed[1]),
110→    opacity: rand(layer.opacity[0], layer.opacity[1]),
111→    lineWidth: rand(layer.width[0], layer.width[1]),
112→    canSplash,
113→  };
114→}
115→
116→function initDrops(width: number, height: number): void {
117→  const items: Raindrop[] = [];
118→  for (let li = 0; li < LAYERS.length; li++) {
119→    const layer = LAYERS[li];
120→    const canSplash = li >= 1; // mid + near
121→    for (let i = 0; i < layer.count; i++) {
122→      items.push(createDrop(width, height, layer, true, canSplash));
123→    }
124→  }
125→  drops = items;
126→  splashes = [];
127→}
128→
129→function spawnSplash(x: number, y: number): void {
130→  if (splashes.length >= MAX_SPLASHES) return;
131→  splashes.push({
132→    x,
133→    y,
134→    radius: 0.5,
135→    maxRadius: rand(3, 8),
136→    opacity: rand(0.15, 0.3),
137→    fadeSpeed: rand(0.004, 0.01),
138→    expandSpeed: rand(0.15, 0.4),
139→  });
140→}
141→
142→function updateAndDraw(_time: number): void {
143→  if (!ctx || !canvas) return;
144→
145→  const { width, height } = canvas;
146→  ctx.clearRect(0, 0, width, height);
147→
148→  // --- Draw rain streaks ---
149→  ctx.lineCap = 'round';
150→
151→  let currentOpacity = -1;
152→  let currentWidth = -1;
153→  let visibleDropCount = 0;
154→
155→  for (const d of drops) {
156→    const prevY = d.y;
157→
158→    // Move
159→    d.x += d.speed * WIND_DX;
160→    d.y += d.speed * WIND_DY;
161→
162→    // Off-screen bottom
163→    if (d.y > height + d.length) {
164→      if (state === 'draining') {
165→        // Spawn one final splash as the drop exits (only on first crossing)
166→        if (prevY <= height + d.length && d.canSplash && Math.random() < 0.35) {
167→          spawnSplash(d.x, height - 1);
168→        }
169→        continue;
170→      }
171→      // Normal: recycle + splash
172→      if (d.canSplash && Math.random() < 0.35) {
173→        spawnSplash(d.x, height - 1);
174→      }
175→      d.y = -(d.length + Math.random() * height * 0.2);
176→      d.x = Math.random() * (width + 100) - 50;
177→    }
178→
179→    // Off-screen right (wind pushes drops rightward)
180→    if (d.x > width + 50) {
181→      if (state === 'draining') {
182→        continue;
183→      }
184→      d.x = -50;
185→    }
186→
187→    visibleDropCount++;
188→
189→    // Batch strokeStyle
190→    const qo = Math.round(d.opacity * 30) / 30;
191→    if (qo !== currentOpacity) {
192→      currentOpacity = qo;
193→      ctx.strokeStyle = `rgba(180,200,220,${currentOpacity})`;
194→    }
195→    const qw = Math.round(d.lineWidth * 4) / 4;
196→    if (qw !== currentWidth) {
197→      currentWidth = qw;
198→      ctx.lineWidth = currentWidth;
199→    }
200→
201→    ctx.beginPath();
202→    ctx.moveTo(d.x, d.y);
203→    ctx.lineTo(d.x + d.length * WIND_DX, d.y + d.length * WIND_DY);
204→    ctx.stroke();
205→  }
206→
207→  // --- Draw splashes ---
208→  ctx.lineWidth = 0.6;
209→  for (let i = splashes.length - 1; i >= 0; i--) {
210→    const s = splashes[i];
211→    s.radius += s.expandSpeed;
212→    s.opacity -= s.fadeSpeed;
213→
214→    if (s.opacity <= 0 || s.radius >= s.maxRadius) {
215→      splashes.splice(i, 1);
216→      continue;
217→    }
218→
219→    ctx.strokeStyle = `rgba(180,200,220,${s.opacity})`;
220→    ctx.beginPath();
221→    ctx.ellipse(s.x, s.y, s.radius, s.radius * 0.35, 0, 0, Math.PI * 2);
222→    ctx.stroke();
223→  }
224→
225→  // All drops off-screen and all splashes faded — finish draining
226→  if (state === 'draining' && visibleDropCount === 0 && splashes.length === 0) {
227→    finalizeDrain();
228→    return;
229→  }
230→
231→  animationFrameId = requestAnimationFrame(updateAndDraw);
232→}
233→
234→function resizeCanvas(): void {
235→  if (!canvas) return;
236→  canvas.width = window.innerWidth;
237→  canvas.height = window.innerHeight;
238→}
239→
240→function startAnimation(): void {
241→  if (animationFrameId !== null) return;
242→  animationFrameId = requestAnimationFrame(updateAndDraw);
243→}
244→
245→function stopAnimation(): void {
246→  if (animationFrameId !== null) {
247→    cancelAnimationFrame(animationFrameId);
248→    animationFrameId = null;
249→  }
250→}
251→
252→function handleVisibilityChange(): void {
253→  if (document.visibilityState === 'visible') {
254→    startAnimation();
255→  } else {
256→    stopAnimation();
257→  }
258→}
259→
260→function enable(): void {
261→  if (state === 'active') return;
262→  if (state === 'draining') {
263→    // Cancel drain — resume normal drop recycling
264→    state = 'active';
265→    return;
266→  }
267→  state = 'active';
268→
269→  canvas = document.createElement('canvas');
270→  canvas.id = CANVAS_ID;
271→  canvas.style.cssText =
272→    'position:fixed;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:2147483647;';
273→  document.documentElement.appendChild(canvas);
274→
275→  ctx = canvas.getContext('2d');
276→  if (!ctx) {
277→    forceDisable();
278→    return;
279→  }
280→
281→  resizeCanvas();
282→  initDrops(canvas.width, canvas.height);
283→  startAnimation();
284→
285→  resizeHandler = resizeCanvas;
286→  window.addEventListener('resize', resizeHandler);
287→
288→  visibilityHandler = handleVisibilityChange;
289→  document.addEventListener('visibilitychange', visibilityHandler);
290→}
291→
292→/**
293→ * Graceful disable: stop spawning new drops and let existing ones
294→ * fall off with final splash ripples.
295→ */
296→function disable(): void {
297→  if (state !== 'active') return;
298→  state = 'draining';
299→}
300→
301→/** Complete the drain: remove canvas and clean up all resources. */
302→function finalizeDrain(): void {
303→  state = 'off';
304→  stopAnimation();
305→
306→  if (resizeHandler) {
307→    window.removeEventListener('resize', resizeHandler);
308→    resizeHandler = null;
309→  }
310→
311→  if (visibilityHandler) {
312→    document.removeEventListener('visibilitychange', visibilityHandler);
313→    visibilityHandler = null;
314→  }
315→
316→  if (canvas) {
317→    canvas.remove();
318→    canvas = null;
319→  }
320→
321→  ctx = null;
322→  drops = [];
323→  splashes = [];
324→}
325→
326→/** Immediate disable: remove everything without draining (e.g. page unload). */
327→function forceDisable(): void {
328→  if (state === 'off') return;
329→  finalizeDrain();
330→}
331→
332→function resolveEffect(res: Record<string, unknown>): string {
333→  if (typeof res[STORAGE_KEY] === 'string') return res[STORAGE_KEY] as string;
334→  if (res[LEGACY_KEY] === true) return 'snow';
335→  return 'off';
336→}
337→
338→export function startRainEffect(): void {
339→  try {
340→    chrome.storage?.sync?.get({ [STORAGE_KEY]: null, [LEGACY_KEY]: false }, (res) => {
341→      if (resolveEffect(res) === EFFECT_VALUE) {
342→        enable();
343→      }
344→    });
345→  } catch (e) {
346→    console.error('[Gemini Voyager] Failed to get rain effect setting:', e);
347→  }
348→
349→  try {
350→    chrome.storage?.onChanged?.addListener((changes, area) => {
351→      if (area === 'sync' && changes[STORAGE_KEY]) {
352→        if (changes[STORAGE_KEY].newValue === EFFECT_VALUE) {
353→          enable();
354→        } else {
355→          disable();
356→        }
357→      }
358→    });
359→  } catch (e) {
360→    console.error('[Gemini Voyager] Failed to add storage listener for rain effect:', e);
361→  }
362→
363→  window.addEventListener('beforeunload', () => {
364→    forceDisable();
365→  });
366→}
