  1→/**
  2→ * Snow Effect for Gemini
  3→ *
  4→ * When enabled, renders a fullscreen canvas snow animation.
  5→ * Uses `pointer-events: none` so it never blocks page interactions.
  6→ * Pauses when the tab is hidden to save CPU.
  7→ *
  8→ * Graceful transitions: when switching effects or disabling, existing
  9→ * snowflakes continue falling naturally instead of vanishing instantly.
 10→ * New snowflakes stop spawning, and the canvas is cleaned up once all
 11→ * particles have left the viewport.
 12→ *
 13→ * Performance notes:
 14→ * - Single canvas with simple arc draws (no images, no shadows)
 15→ * - Snowflakes sorted by opacity at init; drawn in batches to minimize fillStyle switches
 16→ * - Animation pauses on hidden tabs via visibilitychange
 17→ * - ~160 particles total — negligible GPU/CPU overhead
 18→ */
 19→
 20→const CANVAS_ID = 'gv-snow-effect-canvas';
 21→const STORAGE_KEY = 'gvVisualEffect';
 22→const LEGACY_KEY = 'gvSnowEffect';
 23→const EFFECT_VALUE = 'snow';
 24→
 25→/**
 26→ * Three layers simulate depth-of-field:
 27→ *   dust  – tiny background particles, slow, faint
 28→ *   mid   – main visible snowflakes
 29→ *   large – sparse foreground flakes, faster, more opaque
 30→ */
 31→const LAYERS = [
 32→  // dust
 33→  {
 34→    count: 100,
 35→    radius: [0.15, 0.45],
 36→    speed: [0.15, 0.4],
 37→    opacity: [0.15, 0.35],
 38→    drift: [0.05, 0.2],
 39→  },
 40→  // mid
 41→  { count: 80, radius: [0.5, 1.0], speed: [0.4, 1.0], opacity: [0.3, 0.6], drift: [0.15, 0.45] },
 42→  // large
 43→  { count: 60, radius: [1.2, 2.5], speed: [0.8, 1.6], opacity: [0.5, 0.8], drift: [0.25, 0.6] },
 44→] as const;
 45→
 46→interface Snowflake {
 47→  x: number;
 48→  y: number;
 49→  radius: number;
 50→  opacity: number;
 51→  speedY: number;
 52→  drift: number;
 53→  /** Individual oscillation frequency so flakes don't sway in unison */
 54→  driftFreq: number;
 55→  phase: number;
 56→}
 57→
 58→/** Effect lifecycle: off → active ⇄ draining → off */
 59→let state: 'off' | 'active' | 'draining' = 'off';
 60→let canvas: HTMLCanvasElement | null = null;
 61→let ctx: CanvasRenderingContext2D | null = null;
 62→let animationFrameId: number | null = null;
 63→let snowflakes: Snowflake[] = [];
 64→let resizeHandler: (() => void) | null = null;
 65→let visibilityHandler: (() => void) | null = null;
 66→
 67→/** Random float in [min, max) */
 68→function rand(min: number, max: number): number {
 69→  return min + Math.random() * (max - min);
 70→}
 71→
 72→function createSnowflake(
 73→  canvasWidth: number,
 74→  canvasHeight: number,
 75→  layer: (typeof LAYERS)[number],
 76→  randomY: boolean,
 77→): Snowflake {
 78→  return {
 79→    x: Math.random() * canvasWidth,
 80→    y: randomY ? Math.random() * canvasHeight : -(Math.random() * canvasHeight),
 81→    radius: rand(layer.radius[0], layer.radius[1]),
 82→    opacity: rand(layer.opacity[0], layer.opacity[1]),
 83→    speedY: rand(layer.speed[0], layer.speed[1]),
 84→    drift: rand(layer.drift[0], layer.drift[1]),
 85→    driftFreq: rand(0.0003, 0.0012),
 86→    phase: Math.random() * Math.PI * 2,
 87→  };
 88→}
 89→
 90→function initSnowflakes(width: number, height: number): void {
 91→  const flakes: Snowflake[] = [];
 92→  for (const layer of LAYERS) {
 93→    for (let i = 0; i < layer.count; i++) {
 94→      flakes.push(createSnowflake(width, height, layer, true));
 95→    }
 96→  }
 97→  // Sort by opacity so we can batch fillStyle changes during draw
 98→  flakes.sort((a, b) => a.opacity - b.opacity);
 99→  snowflakes = flakes;
100→}
101→
102→function updateAndDraw(time: number): void {
103→  if (!ctx || !canvas) return;
104→
105→  const { width, height } = canvas;
106→  ctx.clearRect(0, 0, width, height);
107→
108→  let currentOpacity = -1;
109→  let visibleCount = 0;
110→
111→  for (const flake of snowflakes) {
112→    flake.y += flake.speedY;
113→    flake.x += Math.sin(flake.phase + time * flake.driftFreq) * flake.drift;
114→
115→    // Recycle when off-screen bottom (or skip during drain)
116→    if (flake.y > height + flake.radius) {
117→      if (state === 'draining') {
118→        continue;
119→      }
120→      flake.y = -flake.radius;
121→      flake.x = Math.random() * width;
122→    }
123→
124→    visibleCount++;
125→
126→    // Wrap horizontal
127→    if (flake.x > width + flake.radius) {
128→      flake.x = -flake.radius;
129→    } else if (flake.x < -flake.radius) {
130→      flake.x = width + flake.radius;
131→    }
132→
133→    // Batch fillStyle: only update when opacity changes (quantised to 2 decimals)
134→    const quantised = Math.round(flake.opacity * 50) / 50;
135→    if (quantised !== currentOpacity) {
136→      currentOpacity = quantised;
137→      ctx.fillStyle = `rgba(255,255,255,${currentOpacity})`;
138→    }
139→
140→    ctx.beginPath();
141→    ctx.arc(flake.x, flake.y, flake.radius, 0, Math.PI * 2);
142→    ctx.fill();
143→  }
144→
145→  // All particles have left the viewport — finish draining
146→  if (state === 'draining' && visibleCount === 0) {
147→    finalizeDrain();
148→    return;
149→  }
150→
151→  animationFrameId = requestAnimationFrame(updateAndDraw);
152→}
153→
154→function resizeCanvas(): void {
155→  if (!canvas) return;
156→  canvas.width = window.innerWidth;
157→  canvas.height = window.innerHeight;
158→}
159→
160→function startAnimation(): void {
161→  if (animationFrameId !== null) return;
162→  animationFrameId = requestAnimationFrame(updateAndDraw);
163→}
164→
165→function stopAnimation(): void {
166→  if (animationFrameId !== null) {
167→    cancelAnimationFrame(animationFrameId);
168→    animationFrameId = null;
169→  }
170→}
171→
172→function handleVisibilityChange(): void {
173→  if (document.visibilityState === 'visible') {
174→    startAnimation();
175→  } else {
176→    stopAnimation();
177→  }
178→}
179→
180→function enable(): void {
181→  if (state === 'active') return;
182→  if (state === 'draining') {
183→    // Cancel drain — resume normal particle recycling
184→    state = 'active';
185→    return;
186→  }
187→  state = 'active';
188→
189→  canvas = document.createElement('canvas');
190→  canvas.id = CANVAS_ID;
191→  canvas.style.cssText =
192→    'position:fixed;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:2147483647;';
193→  document.documentElement.appendChild(canvas);
194→
195→  ctx = canvas.getContext('2d');
196→  if (!ctx) {
197→    forceDisable();
198→    return;
199→  }
200→
201→  resizeCanvas();
202→  initSnowflakes(canvas.width, canvas.height);
203→  startAnimation();
204→
205→  resizeHandler = resizeCanvas;
206→  window.addEventListener('resize', resizeHandler);
207→
208→  visibilityHandler = handleVisibilityChange;
209→  document.addEventListener('visibilitychange', visibilityHandler);
210→}
211→
212→/**
213→ * Graceful disable: stop spawning new snowflakes and let existing ones
214→ * fall off the bottom of the viewport naturally.
215→ */
216→function disable(): void {
217→  if (state !== 'active') return;
218→  state = 'draining';
219→}
220→
221→/** Complete the drain: remove canvas and clean up all resources. */
222→function finalizeDrain(): void {
223→  state = 'off';
224→  stopAnimation();
225→
226→  if (resizeHandler) {
227→    window.removeEventListener('resize', resizeHandler);
228→    resizeHandler = null;
229→  }
230→
231→  if (visibilityHandler) {
232→    document.removeEventListener('visibilitychange', visibilityHandler);
233→    visibilityHandler = null;
234→  }
235→
236→  if (canvas) {
237→    canvas.remove();
238→    canvas = null;
239→  }
240→
241→  ctx = null;
242→  snowflakes = [];
243→}
244→
245→/** Immediate disable: remove everything without draining (e.g. page unload). */
246→function forceDisable(): void {
247→  if (state === 'off') return;
248→  finalizeDrain();
249→}
250→
251→function resolveEffect(res: Record<string, unknown>): string {
252→  if (typeof res[STORAGE_KEY] === 'string') return res[STORAGE_KEY] as string;
253→  // Backward compat: old boolean snow key -> 'snow'
254→  if (res[LEGACY_KEY] === true) return 'snow';
255→  return 'off';
256→}
257→
258→/**
259→ * Initialize and start the snow effect feature
260→ */
261→export function startSnowEffect(): void {
262→  // 1) Read initial setting
263→  try {
264→    chrome.storage?.sync?.get({ [STORAGE_KEY]: null, [LEGACY_KEY]: false }, (res) => {
265→      if (resolveEffect(res) === EFFECT_VALUE) {
266→        enable();
267→      }
268→    });
269→  } catch (e) {
270→    console.error('[Gemini Voyager] Failed to get snow effect setting:', e);
271→  }
272→
273→  // 2) Respond to storage changes
274→  try {
275→    chrome.storage?.onChanged?.addListener((changes, area) => {
276→      if (area === 'sync' && changes[STORAGE_KEY]) {
277→        if (changes[STORAGE_KEY].newValue === EFFECT_VALUE) {
278→          enable();
279→        } else {
280→          disable();
281→        }
282→      }
283→    });
284→  } catch (e) {
285→    console.error('[Gemini Voyager] Failed to add storage listener for snow effect:', e);
286→  }
287→
288→  // 3) Immediate cleanup on page unload (no need to drain)
289→  window.addEventListener('beforeunload', () => {
290→    forceDisable();
291→  });
292→}
