              await Promise.all(
                loadedCustomWebsites.map(async (domain: string) => ({
                  domain,
                  ok: await hasAnyPermission(domain),
                })),
              )
            )
              .filter((item) => item.ok)
              .map((item) => item.domain);

            if (filtered.length !== loadedCustomWebsites.length) {
